SELECT pool_name
FROM storage_pools
WHERE status = 'Failed';

SELECT total_capacity, used_capacity
FROM physical_disks
WHERE status = 'Online' AND health_status = 'Healthy';

SELECT COUNT(*) AS failed_disk_count
FROM physical_disks
WHERE status = 'Failed';

SELECT sp.pool_name
FROM storage_pools sp
WHERE (CAST(sp.used_capacity AS REAL) / CAST(sp.total_capacity AS REAL)) > 0.80;
